import { Link } from "react-router-dom";

function Navbar() {
  return (
    <nav className="bg-black text-white p-4 flex justify-between">
      <Link to="/">🎬 MovieApp</Link>

      <Link to="/favorites">❤️ Favorites</Link>
    </nav>
  );
}

export default Navbar;
